## TUI Wire-Up (in main.go, cmdSetup function)
```go
func cmdSetup(args []string) {
    plat, _ := platform.Detect()
    repoPath := findRepoPath()  // cwd or ~/Projects/Personal/dotfiles
    m, _ := manifest.LoadManifest(filepath.Join(repoPath, "packages.json"))

    model := tui.NewSetupModel(m, plat, repoPath)
    model.SetInstallFunc(func(pkgName string) tui.InstallResult {
        return installPackage(pkgName, m, plat, repoPath, false)
    })

    p := tea.NewProgram(model, tea.WithAltScreen())
    finalModel, _ := p.Run()
    // After TUI exits: run PostStow hooks, save registry
}
```

## installPackage() — the core orchestration function
This is the central function that both TUI and headless CLI call:
```go
func installPackage(name string, m *manifest.Manifest, plat platform.Info, repoDir string, autoAccept bool) installResult {
    pkg := m.Packages[name]
    result := installResult{name: name}

    // 1. Binary installation
    if !pkg.ConfigOnly {
        if pkgmgr.IsInstalled(pkg.Binary) {
            result.binaryOK = true
            result.binaryMsg = "EXISTS"
        } else {
            mgr, target, err := pkgmgr.Resolve(pkg, plat)
            if err != nil {
                result.binaryMsg = err.Error()
                return result
            }
            if err := mgr.Install(target); err != nil {
                result.binaryMsg = fmt.Sprintf("FAILED: %v", err)
                return result
            }
            result.binaryOK = true
            result.binaryMsg = "INSTALLED"
        }
    }

    // 2. Config linking (stow)
    if pkg.StowDir != "" {
        // Omarchy: skip nvim entirely
        if plat.IsOmarchy && name == "nvim" {
            result.configMsg = "SKIPPED (Omarchy)"
            return result
        }
        // Omarchy: ghostty uses merge hook instead of stow
        if plat.IsOmarchy && name == "ghostty" {
            hooks.RunHook("omarchy_ghostty", hooks.HookContext{...})
            result.configOK = true
            result.configMsg = "MERGED (Omarchy)"
            return result
        }

        stowResult, err := stow.Run(pkg.StowDir, stow.Options{
            Dir: repoDir, Target: plat.Home,
            NoFolding: pkg.NoFolding, Restow: true,
            Force: autoAccept, Platform: plat,
        })
        // Map stowResult to configOK/configMsg
    }

    return result
}
```

## Sudo Keep-Alive (Linux only)
Before the install loop, on Linux:
```go
if plat.OS == "linux" {
    exec.Command("sudo", "-v").Run() // initial prompt
    ctx, cancel := context.WithCancel(context.Background())
    defer cancel()
    go func() {
        ticker := time.NewTicker(4 * time.Minute)
        defer ticker.Stop()
        for {
            select {
            case <-ticker.C:
                exec.Command("sudo", "-v").Run()
            case <-ctx.Done():
                return
            }
        }
    }()
}
```

## Hook Phase Orchestration
After all packages installed:
1. PreInstall hooks already ran (before install loop)
2. PostBinary hooks ran per-package (in installPackage)
3. Now run PostStow hooks: `hooks.RunPhase(hooks.PostStow, hookCtx)`

## Registry Persistence
After install completes, save results to `~/.config/dotfiles/installed.json` via `config.SaveRegistry()`.
Write incrementally (after each package) so partial failures are recoverable.

